import { useState } from 'react'
import { Modal, StarRating } from '../components/UI.jsx'
import { IcoPlus, IcoSearch, IcoHeart, IcoEye, IcoEdit, IcoTrash } from '../components/Icons.jsx'

const inp = { padding:'10px 14px', borderRadius:8, fontSize:13, width:'100%' }
const sel = { padding:'10px 14px', borderRadius:8, fontSize:13, width:'100%', appearance:'none' }

const Field = ({ label, required, children, error }) => (
  <div style={{ display:'flex', flexDirection:'column', gap:5 }}>
    <label style={{ fontSize:12, color:'#8A7A60', fontWeight:500 }}>
      {label}{required && <span style={{ color:'#D4A853', marginLeft:3 }}>*</span>}
    </label>
    {children}
    {error && <span style={{ fontSize:11, color:'#EF4444' }}>{error}</span>}
  </div>
)

const SectionTitle = ({ icon, title }) => (
  <p style={{ fontSize:11, color:'#D4A853', fontWeight:700, textTransform:'uppercase', letterSpacing:'.1em', marginBottom:14, paddingBottom:8, borderBottom:'1px solid rgba(212,168,83,.15)' }}>
    {icon} {title}
  </p>
)

const emptyForm = { name:'', shop:'', price:'', wholesalePrice:'', size:'600├ù600mm', material:'Ceramic', category:'Floor', rating:'4.5', reviews:'0', description:'', inStock:true, image:'' }

const ProductFormModal = ({ open, onClose, onSave, initial }) => {
  const isEdit = !!initial?.id
  const [form, setForm]       = useState(isEdit ? initial : emptyForm)
  const [errors, setErrors]   = useState({})
  const [preview, setPreview] = useState(initial?.image || '')

  const set = (k,v) => { setForm(f=>({...f,[k]:v})); setErrors(e=>({...e,[k]:''})) }

  const handleFile = (e) => {
    const file = e.target.files[0]; if (!file) return
    const reader = new FileReader()
    reader.onload = ev => { set('image',ev.target.result); setPreview(ev.target.result) }
    reader.readAsDataURL(file)
  }

  const validate = () => {
    const e = {}
    if (!form.name.trim())                                  e.name          = 'Product name is required'
    if (!form.shop.trim())                                  e.shop          = 'Shop / brand is required'
    if (!form.price || isNaN(form.price) || +form.price<=0) e.price         = 'Valid single price required'
    if (!form.wholesalePrice || isNaN(form.wholesalePrice) || +form.wholesalePrice<=0) e.wholesalePrice = 'Valid wholesale price required'
    if (!form.description.trim())                           e.description   = 'Description is required'
    setErrors(e)
    return !Object.keys(e).length
  }

  const handleSave = () => {
    if (!validate()) return
    onSave({ ...form, price:parseFloat(form.price).toFixed(2), wholesalePrice:parseFloat(form.wholesalePrice).toFixed(2), rating:parseFloat(form.rating||4.5).toFixed(1), reviews:parseInt(form.reviews||0) })
    setForm(emptyForm); setPreview(''); setErrors({}); onClose()
  }

  const handleClose = () => { setForm(emptyForm); setPreview(''); setErrors({}); onClose() }

  // sync when editing a different product
  if (isEdit && initial && form.id !== initial.id) {
    setForm(initial); setPreview(initial.image||'')
  }

  return (
    <Modal open={open} onClose={handleClose} title={isEdit?`Edit ΓÇö ${initial?.name}`:'Add New Product'} width={800}>
      <div style={{ display:'flex', flexDirection:'column', gap:24 }}>
        <div>
          <SectionTitle icon="≡ƒôª" title="Product Information" />
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:16 }}>
            <Field label="Product Name" required error={errors.name}><input className="input-royal" style={inp} placeholder="e.g. Marble Luxe 600" value={form.name} onChange={e=>set('name',e.target.value)} /></Field>
            <Field label="Shop / Brand Name" required error={errors.shop}><input className="input-royal" style={inp} placeholder="e.g. LuxeTile Co." value={form.shop} onChange={e=>set('shop',e.target.value)} /></Field>
            <Field label="Tile Size"><select className="input-royal" style={sel} value={form.size} onChange={e=>set('size',e.target.value)}>{['600├ù600mm','800├ù800mm','300├ù600mm','1200├ù600mm','600├ù1200mm','300├ù300mm','400├ù400mm'].map(s=><option key={s}>{s}</option>)}</select></Field>
            <Field label="Material"><select className="input-royal" style={sel} value={form.material} onChange={e=>set('material',e.target.value)}>{['Ceramic','Vitrified','Porcelain','Natural Stone','Marble','Granite','Mosaic'].map(m=><option key={m}>{m}</option>)}</select></Field>
            <Field label="Category"><select className="input-royal" style={sel} value={form.category} onChange={e=>set('category',e.target.value)}>{['Floor','Wall','Outdoor','Bathroom','Kitchen','Parking'].map(c=><option key={c}>{c}</option>)}</select></Field>
            <Field label="Availability"><select className="input-royal" style={sel} value={form.inStock?'in':'out'} onChange={e=>set('inStock',e.target.value==='in')}><option value="in">In Stock</option><option value="out">Out of Stock</option></select></Field>
          </div>
        </div>

        <div>
          <SectionTitle icon="≡ƒÆ░" title="Pricing & Rating" />
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr 1fr', gap:16 }}>
            <Field label="Single Rate (Γé╣)" required error={errors.price}><input className="input-royal" style={inp} type="number" min="0" placeholder="0.00" value={form.price} onChange={e=>set('price',e.target.value)} /></Field>
            <Field label="Wholesale Rate (Γé╣)" required error={errors.wholesalePrice}><input className="input-royal" style={inp} type="number" min="0" placeholder="0.00" value={form.wholesalePrice} onChange={e=>set('wholesalePrice',e.target.value)} /></Field>
            <Field label="Rating (0ΓÇô5)"><input className="input-royal" style={inp} type="number" min="0" max="5" step="0.1" value={form.rating} onChange={e=>set('rating',e.target.value)} /></Field>
            <Field label="Reviews"><input className="input-royal" style={inp} type="number" min="0" value={form.reviews} onChange={e=>set('reviews',e.target.value)} /></Field>
          </div>
          {(form.price||form.wholesalePrice) && (
            <div style={{ display:'flex', gap:12, marginTop:12 }}>
              {form.price && <div style={{ flex:1, background:'rgba(212,168,83,.07)', border:'1px solid rgba(212,168,83,.2)', borderRadius:10, padding:'10px 16px', display:'flex', justifyContent:'space-between', alignItems:'center' }}><span style={{ fontSize:12, color:'#8A7A60' }}>Single Preview</span><span style={{ fontSize:18, fontWeight:700, color:'#D4A853', fontFamily:"'Playfair Display',serif" }}>Γé╣{parseFloat(form.price||0).toFixed(2)}</span></div>}
              {form.wholesalePrice && <div style={{ flex:1, background:'rgba(34,197,94,.07)', border:'1px solid rgba(34,197,94,.2)', borderRadius:10, padding:'10px 16px', display:'flex', justifyContent:'space-between', alignItems:'center' }}><span style={{ fontSize:12, color:'#8A7A60' }}>Wholesale Preview</span><span style={{ fontSize:18, fontWeight:700, color:'#22C55E', fontFamily:"'Playfair Display',serif" }}>Γé╣{parseFloat(form.wholesalePrice||0).toFixed(2)}</span></div>}
            </div>
          )}
        </div>

        <div>
          <SectionTitle icon="≡ƒû╝∩╕Å" title="Product Image" />
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:16, alignItems:'start' }}>
            <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
              <Field label="Image URL"><input className="input-royal" style={inp} placeholder="https://..." value={form.image&&form.image.startsWith('http')?form.image:''} onChange={e=>{set('image',e.target.value);setPreview(e.target.value)}} /></Field>
              <div style={{ textAlign:'center', color:'#4A3E2C', fontSize:11 }}>ΓÇö OR UPLOAD ΓÇö</div>
              <label style={{ display:'flex', alignItems:'center', gap:10, background:'rgba(212,168,83,.06)', border:'2px dashed rgba(212,168,83,.3)', borderRadius:8, padding:'12px 14px', cursor:'pointer', color:'#D4A853', fontSize:13, fontWeight:500 }}>
                <span style={{ fontSize:20 }}>≡ƒôü</span> Choose Image File
                <input type="file" accept="image/*" onChange={handleFile} style={{ display:'none' }} />
              </label>
            </div>
            <div style={{ background:'#141210', borderRadius:12, overflow:'hidden', border:'1px solid #2A2418', height:160, display:'flex', alignItems:'center', justifyContent:'center' }}>
              {preview ? <img src={preview} alt="Preview" style={{ width:'100%', height:'100%', objectFit:'cover' }} onError={e=>{e.target.src='https://placehold.co/400x300/1A1814/D4A853?text=Invalid'}} />
                : <div style={{ textAlign:'center', color:'#4A3E2C' }}><div style={{ fontSize:36, marginBottom:6 }}>≡ƒÅ╖∩╕Å</div><p style={{ fontSize:11 }}>Preview here</p></div>}
            </div>
          </div>
        </div>

        <div>
          <SectionTitle icon="≡ƒô¥" title="Description" />
          <Field label="Product Description" required error={errors.description}>
            <textarea className="input-royal" placeholder="Describe tile finish, application, quality..." value={form.description} onChange={e=>set('description',e.target.value)} style={{ ...inp, minHeight:90, resize:'vertical', lineHeight:1.6 }} />
          </Field>
        </div>

        <div style={{ display:'flex', gap:12, paddingTop:8, borderTop:'1px solid rgba(42,36,24,.5)' }}>
          <button className="btn-outline" onClick={handleClose} style={{ flex:1, padding:'12px', borderRadius:10, fontSize:14 }}>Cancel</button>
          <button className="btn-gold" onClick={handleSave} style={{ flex:2, padding:'12px', borderRadius:10, fontSize:15, display:'flex', alignItems:'center', justifyContent:'center', gap:8 }}>
            <IcoPlus size={16}/> {isEdit?'Save Changes':'Add Product'}
          </button>
        </div>
      </div>
    </Modal>
  )
}

// ΓöÇΓöÇ Main Products Page ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const ProductsPage = ({ cart, setCart, products, setProducts }) => {
  const [search, setSearch]           = useState('')
  const [filter, setFilter]           = useState({ material:'', category:'', stock:'' })
  const [page, setPage]               = useState(1)
  const [viewProduct, setViewProduct] = useState(null)
  const [editProduct, setEditProduct] = useState(null)
  const [showAdd, setShowAdd]         = useState(false)
  const [wishlist, setWishlist]       = useState([])
  const [toast, setToast]             = useState('')
  const perPage = 8

  const showToast = msg => { setToast(msg); setTimeout(()=>setToast(''), 2500) }

  const filtered = products.filter(p =>
    (p.name.toLowerCase().includes(search.toLowerCase()) || p.shop.toLowerCase().includes(search.toLowerCase())) &&
    (!filter.material || p.material===filter.material) &&
    (!filter.category || p.category===filter.category) &&
    (!filter.stock || (filter.stock==='in' ? p.inStock : !p.inStock))
  )
  const pages = Math.ceil(filtered.length / perPage)
  const shown = filtered.slice((page-1)*perPage, page*perPage)

  const addToCart = (product, type) => {
    const price = type==='wholesale' ? product.wholesalePrice : product.price
    setCart(prev => {
      const ex = prev.find(i=>i.id===product.id&&i.type===type)
      if (ex) return prev.map(i=>i.id===product.id&&i.type===type?{...i,qty:i.qty+1}:i)
      return [...prev,{...product,type,price,qty:1}]
    })
    showToast(`${product.name} (${type}) added to cart!`)
  }

  const handleAdd = data => {
    setProducts(prev => [{...data, id:Date.now()}, ...prev])
    showToast(`Γ£ô "${data.name}" added to catalog!`)
  }

  const handleEdit = data => {
    setProducts(prev => prev.map(p => p.id===data.id ? data : p))
    showToast(`Γ£ô "${data.name}" updated!`)
  }

  const handleDelete = (id, name) => {
    if (window.confirm(`Delete "${name}"?`)) {
      setProducts(prev => prev.filter(p=>p.id!==id))
      showToast(`"${name}" removed.`)
    }
  }

  const toggleWishlist = id => setWishlist(prev=>prev.includes(id)?prev.filter(w=>w!==id):[...prev,id])

  return (
    <div style={{ padding:24 }}>
      {toast && (
        <div className="scale-in" style={{ position:'fixed', top:80, right:24, background:'linear-gradient(135deg,#D4A853,#C8965E)', color:'#0F0E0C', padding:'12px 20px', borderRadius:10, fontWeight:600, fontSize:14, zIndex:9999, boxShadow:'0 8px 24px rgba(212,168,83,.4)' }}>
          {toast}
        </div>
      )}

      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:24 }}>
        <div>
          <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:26, color:'#E8DCC8', marginBottom:4 }}>Product Catalog</h2>
          <p style={{ color:'#6B5E4A', fontSize:13 }}>{filtered.length} of {products.length} products</p>
        </div>
        <button className="btn-gold" onClick={()=>setShowAdd(true)} style={{ padding:'10px 22px', borderRadius:10, fontSize:14, display:'flex', alignItems:'center', gap:8 }}>
          <IcoPlus size={16}/> Add New Product
        </button>
      </div>

      <div style={{ display:'flex', gap:12, marginBottom:24, flexWrap:'wrap' }}>
        <div style={{ position:'relative', flex:1, minWidth:200 }}>
          <input className="input-royal" placeholder="Search products or shop..." value={search} onChange={e=>{setSearch(e.target.value);setPage(1)}} style={{ padding:'10px 12px 10px 38px', borderRadius:10, fontSize:13, width:'100%' }} />
          <span style={{ position:'absolute', left:10, top:'50%', transform:'translateY(-50%)', color:'#6B5E4A' }}><IcoSearch size={16}/></span>
        </div>
        <select className="input-royal" value={filter.material} onChange={e=>{setFilter({...filter,material:e.target.value});setPage(1)}} style={{ padding:'10px 14px', borderRadius:10, fontSize:13, minWidth:130 }}>
          <option value="">Material</option>{['Ceramic','Vitrified','Porcelain','Natural Stone','Marble','Granite','Mosaic'].map(o=><option key={o}>{o}</option>)}
        </select>
        <select className="input-royal" value={filter.category} onChange={e=>{setFilter({...filter,category:e.target.value});setPage(1)}} style={{ padding:'10px 14px', borderRadius:10, fontSize:13, minWidth:130 }}>
          <option value="">Category</option>{['Floor','Wall','Outdoor','Bathroom','Kitchen','Parking'].map(o=><option key={o}>{o}</option>)}
        </select>
        <select className="input-royal" value={filter.stock} onChange={e=>{setFilter({...filter,stock:e.target.value});setPage(1)}} style={{ padding:'10px 14px', borderRadius:10, fontSize:13, minWidth:130 }}>
          <option value="">Stock</option><option value="in">In Stock</option><option value="out">Out of Stock</option>
        </select>
      </div>

      <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:20, marginBottom:24 }}>
        {shown.map((p,i)=>(
          <div key={p.id} className="tile-card card-hover fade-up" style={{ borderRadius:16, overflow:'hidden', animationDelay:`${i*60}ms`, animationFillMode:'both' }}>
            <div style={{ position:'relative' }}>
              <img src={p.image} alt={p.name} style={{ width:'100%', height:180, objectFit:'cover' }} onError={e=>{e.target.src='https://placehold.co/400x300/1A1814/D4A853?text=Tile'}} />
              <div style={{ position:'absolute', top:10, left:10 }}><span className={`badge-stock ${p.inStock?'badge-in':'badge-out'}`}>{p.inStock?'ΓùÅ In Stock':'ΓùÅ Out of Stock'}</span></div>
              <button onClick={()=>toggleWishlist(p.id)} style={{ position:'absolute', top:10, right:10, background:'rgba(15,14,12,.75)', border:'none', borderRadius:'50%', width:30, height:30, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', color:wishlist.includes(p.id)?'#EF4444':'#8A7A60' }}><IcoHeart size={13}/></button>
            </div>
            <div style={{ padding:16 }}>
              <p style={{ fontSize:11, color:'#D4A853', letterSpacing:'.08em', marginBottom:4 }}>{p.shop}</p>
              <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:15, color:'#E8DCC8', marginBottom:8 }}>{p.name}</h3>
              <div style={{ display:'flex', gap:6, flexWrap:'wrap', marginBottom:10 }}>
                {[p.size, p.material, p.category].map(tag=><span key={tag} style={{ background:'rgba(212,168,83,.1)', color:'#D4A853', fontSize:10, padding:'2px 8px', borderRadius:4, fontWeight:500 }}>{tag}</span>)}
              </div>
              <p style={{ fontSize:11, color:'#6B5E4A', lineHeight:1.5, marginBottom:10 }}>{(p.description||'').slice(0,70)}...</p>
              <div style={{ display:'flex', alignItems:'center', gap:6, marginBottom:12 }}><StarRating rating={p.rating}/><span style={{ fontSize:11, color:'#8A7A60' }}>{p.rating} ({p.reviews})</span></div>
              <div style={{ background:'rgba(212,168,83,.05)', borderRadius:8, padding:10, marginBottom:12, border:'1px solid rgba(212,168,83,.1)' }}>
                <div style={{ display:'flex', justifyContent:'space-between', marginBottom:4 }}><span style={{ fontSize:11, color:'#8A7A60' }}>Single</span><span style={{ fontSize:14, fontWeight:700, color:'#D4A853' }}>Γé╣{p.price}</span></div>
                <div style={{ display:'flex', justifyContent:'space-between' }}><span style={{ fontSize:11, color:'#8A7A60' }}>Wholesale</span><span style={{ fontSize:14, fontWeight:700, color:'#22C55E' }}>Γé╣{p.wholesalePrice}</span></div>
              </div>
              <div style={{ display:'flex', flexDirection:'column', gap:6 }}>
                <div style={{ display:'flex', gap:6 }}>
                  <button className="btn-gold" onClick={()=>addToCart(p,'single')} disabled={!p.inStock} style={{ flex:1, padding:'7px', borderRadius:8, fontSize:11 }}>Single</button>
                  <button disabled={!p.inStock} onClick={()=>addToCart(p,'wholesale')} style={{ flex:1, padding:'7px', borderRadius:8, fontSize:11, background:'rgba(34,197,94,.15)', border:'1px solid rgba(34,197,94,.3)', color:'#22C55E', cursor:p.inStock?'pointer':'not-allowed', fontFamily:"'Outfit',sans-serif", fontWeight:600, opacity:p.inStock?1:.5 }}>Wholesale</button>
                </div>
                <div style={{ display:'flex', gap:6 }}>
                  <button className="btn-outline" onClick={()=>setViewProduct(p)} style={{ flex:2, padding:'6px', borderRadius:8, fontSize:11, display:'flex', alignItems:'center', justifyContent:'center', gap:4 }}><IcoEye size={12}/> View</button>
                  <button onClick={()=>setEditProduct(p)} style={{ flex:1, padding:'6px', borderRadius:8, background:'rgba(59,130,246,.12)', border:'1px solid rgba(59,130,246,.25)', color:'#3B82F6', cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center' }}><IcoEdit size={12}/></button>
                  <button onClick={()=>handleDelete(p.id,p.name)} style={{ flex:1, padding:'6px', borderRadius:8, background:'rgba(239,68,68,.12)', border:'1px solid rgba(239,68,68,.25)', color:'#EF4444', cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center' }}><IcoTrash size={12}/></button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div style={{ display:'flex', justifyContent:'center', gap:8 }}>
        {Array.from({length:pages},(_,i)=>i+1).map(p=>(
          <button key={p} onClick={()=>setPage(p)} style={{ width:36, height:36, borderRadius:8, border:page===p?'none':'1px solid #2A2418', cursor:'pointer', fontFamily:"'Outfit',sans-serif", fontWeight:600, fontSize:13, background:page===p?'linear-gradient(135deg,#D4A853,#C8965E)':'#1A1814', color:page===p?'#0F0E0C':'#8A7A60' }}>{p}</button>
        ))}
      </div>

      <ProductFormModal open={showAdd}       onClose={()=>setShowAdd(false)}    onSave={handleAdd}  initial={null} />
      <ProductFormModal open={!!editProduct} onClose={()=>setEditProduct(null)} onSave={handleEdit} initial={editProduct} />

      <Modal open={!!viewProduct} onClose={()=>setViewProduct(null)} title={viewProduct?.name||''} width={700}>
        {viewProduct && (
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:24 }}>
            <img src={viewProduct.image} alt={viewProduct.name} style={{ width:'100%', height:240, objectFit:'cover', borderRadius:12 }} onError={e=>{e.target.src='https://placehold.co/400x300/1A1814/D4A853?text=Tile'}} />
            <div>
              <p style={{ color:'#D4A853', fontSize:12, letterSpacing:'.1em', marginBottom:8 }}>{viewProduct.shop}</p>
              <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:12 }}><StarRating rating={viewProduct.rating}/><span style={{ fontSize:12, color:'#8A7A60' }}>{viewProduct.reviews} reviews</span></div>
              <p style={{ color:'#C8B898', fontSize:13, lineHeight:1.7, marginBottom:16 }}>{viewProduct.description}</p>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8, marginBottom:16 }}>
                {[['Size',viewProduct.size],['Material',viewProduct.material],['Category',viewProduct.category],['Stock',viewProduct.inStock?'In Stock':'Out of Stock']].map(([k,v])=>(
                  <div key={k} style={{ background:'#141210', borderRadius:8, padding:10 }}><p style={{ fontSize:10, color:'#6B5E4A', marginBottom:2 }}>{k}</p><p style={{ fontSize:13, color:'#E8DCC8', fontWeight:500 }}>{v}</p></div>
                ))}
              </div>
              <div style={{ background:'rgba(212,168,83,.06)', border:'1px solid rgba(212,168,83,.2)', borderRadius:10, padding:14, marginBottom:16 }}>
                <div style={{ display:'flex', justifyContent:'space-between', marginBottom:8 }}><span style={{ fontSize:13, color:'#8A7A60' }}>Single Rate</span><span style={{ fontSize:18, fontWeight:700, color:'#D4A853' }}>Γé╣{viewProduct.price}</span></div>
                <div style={{ display:'flex', justifyContent:'space-between' }}><span style={{ fontSize:13, color:'#8A7A60' }}>Wholesale Rate</span><span style={{ fontSize:18, fontWeight:700, color:'#22C55E' }}>Γé╣{viewProduct.wholesalePrice}</span></div>
              </div>
              <div style={{ display:'flex', gap:8 }}>
                <button className="btn-gold" onClick={()=>{addToCart(viewProduct,'single');setViewProduct(null)}} style={{ flex:1, padding:'10px', borderRadius:8, fontSize:13 }}>Add Single</button>
                <button onClick={()=>{addToCart(viewProduct,'wholesale');setViewProduct(null)}} style={{ flex:1, padding:'10px', borderRadius:8, fontSize:13, background:'rgba(34,197,94,.15)', border:'1px solid rgba(34,197,94,.3)', color:'#22C55E', cursor:'pointer', fontFamily:"'Outfit',sans-serif", fontWeight:600 }}>Add Wholesale</button>
              </div>
            </div>
          </div>
        )}
      </Modal>
    </div>
  )
}

export default ProductsPage

import { useState, useMemo } from 'react'
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid,
  Tooltip, ResponsiveContainer, LineChart, Line
} from 'recharts'
import { IcoDownload, IcoPrint, IcoFilter } from '../components/Icons.jsx'

const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec']

const fmtCurrency = (n) => {
  if (n >= 100000) return `Γé╣${(n/100000).toFixed(1)}L`
  if (n >= 1000)   return `Γé╣${(n/1000).toFixed(1)}K`
  return `Γé╣${n.toFixed(0)}`
}

const ReportsPage = ({ sales = [], products = [] }) => {

  // ΓöÇΓöÇ Filter state ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const [dateFrom,       setDateFrom]       = useState('')
  const [dateTo,         setDateTo]         = useState('')
  const [filterProduct,  setFilterProduct]  = useState('')
  const [filterCustomer, setFilterCustomer] = useState('')
  const [filterPayment,  setFilterPayment]  = useState('')
  const [filterStatus,   setFilterStatus]   = useState('')
  const [applied,        setApplied]        = useState(false)

  // ΓöÇΓöÇ Unique customer list from sales ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const customerList = useMemo(() =>
    [...new Set(sales.map(s => s.customer).filter(Boolean))], [sales])

  // ΓöÇΓöÇ Product list from products prop ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const productList = useMemo(() =>
    [...new Set(products.map(p => p.name))], [products])

  // ΓöÇΓöÇ Apply filters ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const filteredSales = useMemo(() => {
    return sales.filter(s => {
      const sDate = s.orderDate ? new Date(s.orderDate) : null

      if (dateFrom && sDate && sDate < new Date(dateFrom)) return false
      if (dateTo   && sDate && sDate > new Date(dateTo))   return false

      if (filterProduct  && s.product       !== filterProduct)  return false
      if (filterCustomer && s.customer      !== filterCustomer) return false
      if (filterPayment  && s.paymentMethod !== filterPayment)  return false
      if (filterStatus   && s.orderStatus   !== filterStatus)   return false

      return true
    })
  }, [sales, dateFrom, dateTo, filterProduct, filterCustomer, filterPayment, filterStatus, applied])

  const handleClear = () => {
    setDateFrom(''); setDateTo('')
    setFilterProduct(''); setFilterCustomer('')
    setFilterPayment(''); setFilterStatus('')
    setApplied(false)
  }

  // ΓöÇΓöÇ Computed summary from filtered data ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const totalRevenue   = filteredSales.reduce((a,s) => a + parseFloat(s.totalAmt||0), 0)
  const totalOrders    = filteredSales.length
  const avgOrderVal    = totalOrders > 0 ? totalRevenue / totalOrders : 0
  const completedCount = filteredSales.filter(s => s.orderStatus === 'Completed').length

  // ΓöÇΓöÇ Monthly chart from filtered data ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const monthlyChart = useMemo(() => {
    const map = {}
    MONTHS.forEach(m => { map[m] = { month:m, sales:0, orders:0 } })
    filteredSales.forEach(s => {
      const d = s.orderDate ? new Date(s.orderDate) : null
      if (!d || isNaN(d)) return
      const mon = MONTHS[d.getMonth()]
      if (map[mon]) {
        map[mon].sales  += parseFloat(s.totalAmt || 0)
        map[mon].orders += 1
      }
    })
    return Object.values(map)
  }, [filteredSales])

  // ΓöÇΓöÇ Top products chart from filtered data ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const topProductsChart = useMemo(() => {
    const map = {}
    filteredSales.forEach(s => {
      if (!s.product) return
      if (!map[s.product]) map[s.product] = { name:s.product, sales:0, revenue:0 }
      map[s.product].sales   += parseInt(s.qty || 0)
      map[s.product].revenue += parseFloat(s.totalAmt || 0)
    })
    return Object.values(map).sort((a,b) => b.sales - a.sales).slice(0,6)
  }, [filteredSales])

  const inpStyle = { padding:'9px 14px', borderRadius:8, fontSize:13 }
  const selStyle = { ...inpStyle, appearance:'none' }

  const LabeledField = ({ label, children }) => (
    <div>
      <label style={{ fontSize:11, color:'#8A7A60', display:'block', marginBottom:6, textTransform:'uppercase', letterSpacing:'.06em' }}>{label}</label>
      {children}
    </div>
  )

  return (
    <div style={{ padding:24 }}>

      {/* Header */}
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:24 }}>
        <div>
          <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:26, color:'#E8DCC8', marginBottom:4 }}>Analytics & Reports</h2>
          <p style={{ color:'#6B5E4A', fontSize:13 }}>
            {filteredSales.length} of {sales.length} records
            {(dateFrom||dateTo||filterProduct||filterCustomer||filterPayment||filterStatus) && (
              <span style={{ color:'#D4A853', marginLeft:8, fontWeight:600 }}>ΓÇö Filters Active</span>
            )}
          </p>
        </div>
        <div style={{ display:'flex', gap:10 }}>
          <button className="btn-outline" style={{ padding:'9px 16px', borderRadius:10, fontSize:13, display:'flex', alignItems:'center', gap:6 }}>
            <IcoDownload size={14}/> Export PDF
          </button>
          <button className="btn-gold" style={{ padding:'9px 16px', borderRadius:10, fontSize:13, display:'flex', alignItems:'center', gap:6 }}>
            <IcoDownload size={14}/> Export Excel
          </button>
          <button className="btn-outline" style={{ padding:'9px 14px', borderRadius:10 }}>
            <IcoPrint size={14}/>
          </button>
        </div>
      </div>

      {/* ΓöÇΓöÇ Filter Panel ΓöÇΓöÇ */}
      <div className="stat-card fade-up" style={{ borderRadius:16, padding:20, marginBottom:24 }}>
        <p style={{ fontSize:12, color:'#D4A853', fontWeight:600, textTransform:'uppercase', letterSpacing:'.08em', marginBottom:16 }}>
          ≡ƒöì Filter Reports
        </p>
        <div style={{ display:'grid', gridTemplateColumns:'repeat(6,1fr)', gap:14, alignItems:'end' }}>

          <LabeledField label="From Date">
            <input type="date" className="input-royal" value={dateFrom}
              onChange={e => setDateFrom(e.target.value)} style={inpStyle} />
          </LabeledField>

          <LabeledField label="To Date">
            <input type="date" className="input-royal" value={dateTo}
              onChange={e => setDateTo(e.target.value)} style={inpStyle} />
          </LabeledField>

          <LabeledField label="Product">
            <select className="input-royal" value={filterProduct}
              onChange={e => setFilterProduct(e.target.value)} style={selStyle}>
              <option value="">All Products</option>
              {productList.map(p => <option key={p} value={p}>{p}</option>)}
            </select>
          </LabeledField>

          <LabeledField label="Customer">
            <select className="input-royal" value={filterCustomer}
              onChange={e => setFilterCustomer(e.target.value)} style={selStyle}>
              <option value="">All Customers</option>
              {customerList.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </LabeledField>

          <LabeledField label="Payment Method">
            <select className="input-royal" value={filterPayment}
              onChange={e => setFilterPayment(e.target.value)} style={selStyle}>
              <option value="">All Methods</option>
              {['Cash','UPI','Card','Online','Bank Transfer'].map(m => <option key={m}>{m}</option>)}
            </select>
          </LabeledField>

          <LabeledField label="Order Status">
            <select className="input-royal" value={filterStatus}
              onChange={e => setFilterStatus(e.target.value)} style={selStyle}>
              <option value="">All Statuses</option>
              {['Completed','Processing','Cancelled'].map(s => <option key={s}>{s}</option>)}
            </select>
          </LabeledField>
        </div>

        {/* Active filter chips + clear */}
        <div style={{ display:'flex', gap:8, marginTop:16, flexWrap:'wrap', alignItems:'center' }}>
          {[
            dateFrom       && { label:`From: ${dateFrom}`,       clear:()=>setDateFrom('') },
            dateTo         && { label:`To: ${dateTo}`,           clear:()=>setDateTo('') },
            filterProduct  && { label:`Product: ${filterProduct}`,   clear:()=>setFilterProduct('') },
            filterCustomer && { label:`Customer: ${filterCustomer}`, clear:()=>setFilterCustomer('') },
            filterPayment  && { label:`Payment: ${filterPayment}`,   clear:()=>setFilterPayment('') },
            filterStatus   && { label:`Status: ${filterStatus}`,     clear:()=>setFilterStatus('') },
          ].filter(Boolean).map((chip,i) => (
            <span key={i} style={{ display:'inline-flex', alignItems:'center', gap:6, background:'rgba(212,168,83,.12)', border:'1px solid rgba(212,168,83,.3)', color:'#D4A853', padding:'4px 10px', borderRadius:20, fontSize:11, fontWeight:500 }}>
              {chip.label}
              <button onClick={chip.clear} style={{ background:'none', border:'none', color:'#D4A853', cursor:'pointer', fontSize:14, lineHeight:1, padding:0 }}>├ù</button>
            </span>
          ))}
          {(dateFrom||dateTo||filterProduct||filterCustomer||filterPayment||filterStatus) && (
            <button onClick={handleClear}
              style={{ background:'rgba(239,68,68,.1)', border:'1px solid rgba(239,68,68,.25)', color:'#EF4444', padding:'4px 12px', borderRadius:20, fontSize:11, fontWeight:600, cursor:'pointer', fontFamily:"'Outfit',sans-serif" }}>
              Clear All ├ù
            </button>
          )}
          {(!dateFrom&&!dateTo&&!filterProduct&&!filterCustomer&&!filterPayment&&!filterStatus) && (
            <span style={{ fontSize:11, color:'#4A3E2C' }}>No filters applied ΓÇö showing all {sales.length} records</span>
          )}
        </div>
      </div>

      {/* ΓöÇΓöÇ Summary Cards (live) ΓöÇΓöÇ */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:16, marginBottom:24 }}>
        {[
          { label:'Total Revenue',   value: fmtCurrency(totalRevenue), raw: `Γé╣${totalRevenue.toLocaleString('en-IN', {minimumFractionDigits:2})}` },
          { label:'Total Orders',    value: totalOrders },
          { label:'Avg Order Value', value: fmtCurrency(avgOrderVal) },
          { label:'Completed',       value: completedCount },
        ].map((s,i) => (
          <div key={s.label} className="stat-card fade-up"
            style={{ borderRadius:12, padding:20, animationDelay:`${i*80}ms`, animationFillMode:'both' }}>
            <p style={{ fontSize:11, color:'#8A7A60', marginBottom:6, textTransform:'uppercase', letterSpacing:'.08em' }}>{s.label}</p>
            <p style={{ fontSize:26, fontWeight:700, color:'#D4A853', fontFamily:"'Playfair Display',serif" }}>{s.value}</p>
            {s.raw && <p style={{ fontSize:10, color:'#4A3E2C', marginTop:2 }}>{s.raw}</p>}
          </div>
        ))}
      </div>

      {/* ΓöÇΓöÇ Charts ΓöÇΓöÇ */}
      <div style={{ display:'grid', gridTemplateColumns:'3fr 2fr', gap:16, marginBottom:24 }}>

        {/* Monthly Revenue Bar */}
        <div className="stat-card" style={{ borderRadius:16, padding:24 }}>
          <div style={{ marginBottom:20 }}>
            <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:17, color:'#E8DCC8', marginBottom:2 }}>Monthly Sales Revenue</h3>
            <p style={{ fontSize:11, color:'#6B5E4A' }}>Based on filtered data</p>
          </div>
          {filteredSales.length > 0 ? (
            <ResponsiveContainer width="100%" height={220}>
              <BarChart data={monthlyChart}>
                <defs>
                  <linearGradient id="goldGrad4" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor="#D4A853"/>
                    <stop offset="100%" stopColor="#C8965E" stopOpacity={0.6}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="#1E1C17" />
                <XAxis dataKey="month" stroke="#6B5E4A" fontSize={11} />
                <YAxis stroke="#6B5E4A" fontSize={11} tickFormatter={v => v>=1000?`${(v/1000).toFixed(0)}K`:v} />
                <Tooltip
                  contentStyle={{ background:'#1A1814', border:'1px solid #2A2418', borderRadius:8, color:'#E8DCC8' }}
                  formatter={v => [`Γé╣${v.toLocaleString()}`, 'Revenue']}
                />
                <Bar dataKey="sales" fill="url(#goldGrad4)" radius={[4,4,0,0]} />
              </BarChart>
            </ResponsiveContainer>
          ) : (
            <div style={{ display:'flex', alignItems:'center', justifyContent:'center', height:220, color:'#4A3E2C', flexDirection:'column', gap:8 }}>
              <div style={{ fontSize:32 }}>≡ƒôë</div>
              <p style={{ fontSize:13 }}>No data matches current filters</p>
            </div>
          )}
        </div>

        {/* Top Products Horizontal Bar */}
        <div className="stat-card" style={{ borderRadius:16, padding:24 }}>
          <div style={{ marginBottom:20 }}>
            <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:17, color:'#E8DCC8', marginBottom:2 }}>Top Selling Products</h3>
            <p style={{ fontSize:11, color:'#6B5E4A' }}>By units sold in filtered range</p>
          </div>
          {topProductsChart.length > 0 ? (
            <ResponsiveContainer width="100%" height={220}>
              <BarChart data={topProductsChart} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" stroke="#1E1C17" />
                <XAxis type="number" stroke="#6B5E4A" fontSize={11} />
                <YAxis dataKey="name" type="category" stroke="#6B5E4A" fontSize={10} width={90}
                  tickFormatter={v => v.length > 12 ? v.slice(0,12)+'ΓÇª' : v} />
                <Tooltip
                  contentStyle={{ background:'#1A1814', border:'1px solid #2A2418', borderRadius:8, color:'#E8DCC8' }}
                  formatter={v => [`${v} units`, 'Sold']}
                />
                <Bar dataKey="sales" fill="#D4A853" radius={[0,4,4,0]} />
              </BarChart>
            </ResponsiveContainer>
          ) : (
            <div style={{ display:'flex', alignItems:'center', justifyContent:'center', height:220, color:'#4A3E2C', flexDirection:'column', gap:8 }}>
              <div style={{ fontSize:32 }}>≡ƒôª</div>
              <p style={{ fontSize:13 }}>No product data</p>
            </div>
          )}
        </div>
      </div>

      {/* ΓöÇΓöÇ Sales Report Table ΓöÇΓöÇ */}
      <div className="stat-card" style={{ borderRadius:16, overflow:'hidden' }}>
        <div style={{ padding:'16px 24px', borderBottom:'1px solid #1E1C17', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <div>
            <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:17, color:'#E8DCC8', marginBottom:2 }}>Sales Report Table</h3>
            <p style={{ fontSize:11, color:'#6B5E4A' }}>{filteredSales.length} records shown</p>
          </div>
          <div style={{ display:'flex', gap:8 }}>
            <button className="btn-outline" style={{ padding:'6px 14px', borderRadius:8, fontSize:12, display:'flex', alignItems:'center', gap:4 }}>
              <IcoDownload size={12}/> PDF
            </button>
            <button className="btn-gold" style={{ padding:'6px 14px', borderRadius:8, fontSize:12, display:'flex', alignItems:'center', gap:4 }}>
              <IcoDownload size={12}/> Excel
            </button>
          </div>
        </div>

        {filteredSales.length > 0 ? (
          <div style={{ overflowX:'auto' }}>
            <table className="table-royal">
              <thead>
                <tr>
                  <th>Order ID</th><th>Customer</th><th>Product</th>
                  <th>Qty</th><th>Price/Unit</th><th>Discount</th>
                  <th>Total</th><th>Payment</th><th>Status</th><th>Date</th>
                </tr>
              </thead>
              <tbody>
                {filteredSales.map(s => (
                  <tr key={s.id}>
                    <td style={{ color:'#D4A853', fontWeight:600 }}>{s.id}</td>
                    <td>{s.customer}</td>
                    <td>{s.product}</td>
                    <td style={{ textAlign:'center' }}>{s.qty}</td>
                    <td>Γé╣{s.pricePerUnit}</td>
                    <td style={{ color:'#22C55E' }}>{s.discount}%</td>
                    <td style={{ color:'#22C55E', fontWeight:600 }}>Γé╣{s.totalAmt}</td>
                    <td>{s.paymentMethod}</td>
                    <td>
                      <span style={{ padding:'2px 10px', borderRadius:20, fontSize:11, fontWeight:600,
                        background: s.orderStatus==='Completed'?'rgba(34,197,94,.15)':s.orderStatus==='Processing'?'rgba(234,179,8,.15)':'rgba(239,68,68,.15)',
                        color: s.orderStatus==='Completed'?'#22C55E':s.orderStatus==='Processing'?'#EAB308':'#EF4444' }}>
                        {s.orderStatus}
                      </span>
                    </td>
                    <td style={{ fontSize:12 }}>{s.orderDate}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div style={{ display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:48, color:'#4A3E2C' }}>
            <div style={{ fontSize:40, marginBottom:12 }}>≡ƒöì</div>
            <p style={{ fontSize:15, color:'#6B5E4A', marginBottom:6 }}>No records match your filters</p>
            <p style={{ fontSize:12, color:'#4A3E2C', marginBottom:16 }}>Try adjusting or clearing the filters above</p>
            <button onClick={handleClear}
              style={{ background:'rgba(212,168,83,.1)', border:'1px solid rgba(212,168,83,.3)', color:'#D4A853', padding:'8px 20px', borderRadius:8, fontSize:13, cursor:'pointer', fontFamily:"'Outfit',sans-serif", fontWeight:500 }}>
              Clear All Filters
            </button>
          </div>
        )}
      </div>
    </div>
  )
}

export default ReportsPage
